INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (1, 'Procesion del Senor de los Temblores', 'Mariano Fuentes Lira', 18500, 'Oleo sobre lienzo de gran formato que retrata la procesion central del Cusco con detalle minucioso en los mantos bordados y la arquitectura colonial de la Plaza de Armas. Obra de referencia del barroco andino del siglo XX.', 'https://images.unsplash.com/photo-1578926375605-eaf7559b1458?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (2, 'Virgen del Carmen de Paucartambo', 'Edilberto Merida', 12750, 'Pieza de la escuela cusquena contemporanea inspirada en la festividad mariana de Paucartambo. Tecnica mixta con pan de oro y pigmentos minerales. Certificada por el Ministerio de Cultura del Peru.', 'https://images.unsplash.com/photo-1582555172866-f73bb12a2ab3?w=1200', 'https://modelviewer.dev/shared-assets/models/Astronaut.glb', 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (3, 'Retablo de Ollantaytambo', 'Hilario Mendivil', 22300, 'Retablo en madera policromada que recrea escenas del Valle Sagrado y la cosmovision andina. Trabajo en yeso de papa con acabado en esmalte. Pieza unica de alto valor etnografico.', 'https://images.unsplash.com/photo-1577083552431-6e5fd01988ec?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (4, 'Pachamama bajo la Cruz del Sur', 'Maximiliana Palomino', 9800, 'Tecnica mixta sobre tabla con pigmentos minerales del Valle. Sintesis entre lo prehispanico y lo barroco andino. La obra explora la dualidad cosmologica inca a traves de simbolos geometricos y figuras zoomorfas.', 'https://images.unsplash.com/photo-1549887534-1541e9326642?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (5, 'Mercado de San Pedro', 'Antonio Olave', 7600, 'Escena costumbrista que documenta el comercio tradicional del Cusco a inicios del siglo XX.', 'https://images.unsplash.com/photo-1513519245088-0e12902e5a38?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 15:11:18');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (6, 'Inti Raymi, ofrenda solar', 'Mariano Fuentes Lira', 31200, 'Pieza monumental 180x240 cm que captura la ceremonia del Inti Raymi en la Fortaleza de Sacsayhuaman con simbolismo incaico y pinceladas neobarrocas. Presentada en la Bienal de Arte Andino 2019.', 'https://images.unsplash.com/photo-1577720643272-265f09367456?w=1200', 'https://modelviewer.dev/shared-assets/models/Astronaut.glb', 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (7, 'Choquequirao en la bruma', 'Edilberto Merida', 14400, 'Paisaje contemplativo del complejo arqueologico de Choquequirao visto desde el mirador de Capuliyoc. Oleo sobre tela de algodon andino con imprimatura ocre. Atmosfera niebla matinal capturada in situ.', 'https://images.unsplash.com/photo-1526481280699-c40e3d68fdf2?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (8, 'Tejedoras de Chinchero', 'Maximiliana Palomino', 8900, 'Retrato colectivo de las maestras tejedoras de Chinchero, custodias del telar de cintura ancestral. Tecnica acuarela sobre papel Fabriano 300g con trazos en tinta ferrogalica.', 'https://images.unsplash.com/photo-1604079628040-94301bb21b91?w=1200', NULL, 'available', '2026-05-20 15:11:18', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (9, 'Mercado de San Pedro al amanecer', 'Antonio Olave Palomino', 7600, 'Escena costumbrista que documenta el comercio tradicional del Cusco a inicios del siglo XX. Oleo sobre tela con influencia de la pintura academica limena y la tradicion narrativa andina.', 'https://images.unsplash.com/photo-1513519245088-0e12902e5a38?w=1200', NULL, 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (10, 'La Ultima Cena Andina', 'Marcos Zapata (replica documentada)', 45000, 'Replica documentada y certificada de la celebre obra de la Catedral del Cusco que muestra la Ultima Cena con elementos gastronomicos andinos. Ejecutada con criterios de alta fidelidad cromatica y compositiva.', 'https://images.unsplash.com/photo-1561214115-f2f134cc4912?w=1200', 'https://modelviewer.dev/shared-assets/models/Astronaut.glb', 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (11, 'Nevado Ausangate en verano', 'Victor Delfin Quiroga', 16800, 'Vista del Ausangate a 6384 metros durante el solsticio de diciembre. Pintura al oleo con espátula sobre tela gruesa. Paleta fria y luminosa que evoca la experiencia mistica del Qoyllur Riti.', 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=1200', NULL, 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (12, 'Danzantes de Tijeras', 'Joaquin Lopez Antay', 11200, 'Representacion de los danzantes de tijeras de Ayacucho en plena competencia ritual. Obra en acrilico sobre tela con superposicion de capas veladas. Patrimonio Cultural de la Nacion declarado por la UNESCO.', 'https://images.unsplash.com/photo-1547036967-23d11aacaee0?w=1200', NULL, 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (13, 'Quechua madre e hijo', 'Hilario Mendivil', 19500, 'Escultura en yeso de papa pintada al frio que representa la iconografia maternal andina. Serie Nacimiento del mundo, pieza central. Cuello elongado caracteristico de la escuela mendivil reconocida internacionalmente.', 'https://images.unsplash.com/photo-1555685812-4b943f1cb0eb?w=1200', 'https://modelviewer.dev/shared-assets/models/Astronaut.glb', 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (14, 'Plaza Mayor del Cusco 1890', 'Juan de Espinosa Medrano (atribuida)', 52000, 'Obra atribuida documentalmente al periodo colonial tardio. Vista panoramica de la Plaza Mayor del Cusco con fuente central y calesas. Oleo sobre lienzo encolado en tabla de cedro andino.', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200', NULL, 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (15, 'Chakana cosmica', 'Maximiliana Palomino', 6400, 'Serie geometrica sobre la cruz andina como eje del universo. Tecnica mixta, oro fino y arcilla cocida sobre panel de madera. Pieza de coleccion de formato reducido 40x40 cm.', 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?w=1200', NULL, 'available', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
INSERT INTO "artworks" ("id", "title", "artist_name", "price", "description", "image_url", "model_3d_url", "status", "created_at", "updated_at") VALUES (16, 'Rio Urubamba en agosto', 'Victor Delfin Quiroga', 13300, 'Vista del Rio Urubamba a su paso por el Valle Sagrado en epoca de estiaje. Impresionismo andino con influencia de la escuela de Barbizon. Colores ocres y verdes que evocan la temporada seca del altiplano.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1200', NULL, 'sold', '2026-05-20 16:26:15', '2026-05-20 16:26:15');
